var ANSWER = Infer({method: 'MCMC', samples: 1000}, function() {
  var strength = mem(function(person) { return gaussian(0, 1); });
  var lazy = function(person) { return flip(0.25); };
  var pulling = function(person) {
    return lazy(person) ? strength(person) * 0.5 : strength(person);
  };
  var totalPulling = function(team) { return sum(map(pulling, team)); };
  var winner = function(team1, team2) {
    return totalPulling(team1) > totalPulling(team2) ? team1 : team2;
  };
  var beat = function(team1, team2) { return winner(team1, team2) == team1; };

  condition(beat(['bob', 'alice'], ['tom', 'sue']));
  condition(beat(['bob', 'alice'], ['sue', 'jim']));

  return strength('bob');
});

